// ============================================================================
// CSV Parser Library
// ============================================================================

/** Configuration options for the CSV parser */
export interface CSVOptions {
  /** Field delimiter character (default: ",") */
  delimiter?: string;
  /** Quote character for wrapping fields (default: '"') */
  quote?: string;
  /** Line separator (default: auto-detect \r\n, \n, or \r) */
  lineSeparator?: string;
  /** Whether to automatically coerce types (default: true) */
  typeCoercion?: boolean;
}

/** Represents a parsing error on a specific row */
export interface CSVError {
  row: number;
  message: string;
}

/** A single parsed row as a record of string keys to coerced values */
export type CSVRow = Record<string, unknown>;

/** The result object returned by parseCSV */
export interface CSVResult {
  /** Parsed data rows as an array of objects keyed by header names */
  rows: CSVRow[];
  /** Column header names from the first row */
  headers: string[];
  /** Errors encountered during parsing (malformed rows, etc.) */
  errors: CSVError[];
  /** Return a new CSVResult containing only rows matching the predicate */
  filter(predicate: (row: CSVRow) => boolean): CSVResult;
  /** Sum all numeric values in the given column */
  sum(column: string): number;
  /** Average all numeric values in the given column */
  average(column: string): number;
  /** Count total rows */
  count(): number;
  /** Group rows by the values in the given column */
  groupBy(column: string): Map<unknown, CSVRow[]>;
}

// ============================================================================
// Internal helpers
// ============================================================================

/**
 * Coerce a raw string value to its detected type.
 *  - empty string / "null" / "NULL" → null
 *  - "true"/"false" (case-insensitive) → boolean
 *  - numeric strings → number
 *  - everything else → string (unchanged)
 */
function coerceValue(raw: string): unknown {
  // Null detection
  if (raw === "" || raw.toLowerCase() === "null") {
    return null;
  }

  // Boolean detection (case-insensitive)
  const lower = raw.toLowerCase();
  if (lower === "true") return true;
  if (lower === "false") return false;

  // Numeric detection – must be a finite number and not just whitespace
  if (raw.trim() !== "" && !isNaN(Number(raw)) && isFinite(Number(raw))) {
    return Number(raw);
  }

  return raw;
}

/**
 * Parse a single CSV line (or partial lines when quotes span newlines) into
 * an array of raw string field values using a state-machine approach.
 *
 * Returns { fields, complete } where complete=false means we need more input
 * (an unclosed quoted field spanning multiple lines).
 */
function parseFields(
  input: string,
  delimiter: string,
  quote: string
): { fields: string[]; complete: boolean } {
  const fields: string[] = [];
  let current = "";
  let inQuotes = false;
  let i = 0;

  while (i < input.length) {
    const ch = input[i];

    if (inQuotes) {
      if (ch === quote) {
        // Peek ahead: escaped quote (doubled)?
        if (i + 1 < input.length && input[i + 1] === quote) {
          current += quote;
          i += 2;
          continue;
        }
        // Closing quote
        inQuotes = false;
        i++;
        continue;
      }
      current += ch;
      i++;
    } else {
      if (ch === quote) {
        // Opening quote – only valid at field start or right after delimiter
        inQuotes = true;
        i++;
        continue;
      }
      if (ch === delimiter) {
        fields.push(current);
        current = "";
        i++;
        continue;
      }
      current += ch;
      i++;
    }
  }

  // Push the last field
  fields.push(current);

  return { fields, complete: !inQuotes };
}

/**
 * Split raw CSV text into logical lines, correctly handling quoted fields that
 * contain line breaks. Returns an array of raw line strings where each entry
 * is a complete record (quotes are balanced).
 */
function splitLines(
  input: string,
  lineSeparator: string | undefined,
  quote: string
): string[] {
  // If an explicit line separator is given, use a simpler but still
  // quote-aware split.
  const lines: string[] = [];
  let current = "";
  let inQuotes = false;
  let i = 0;

  // Determine what counts as a line break
  const isLineSep = (pos: number): { match: boolean; length: number } => {
    if (lineSeparator !== undefined) {
      if (input.substring(pos, pos + lineSeparator.length) === lineSeparator) {
        return { match: true, length: lineSeparator.length };
      }
      return { match: false, length: 0 };
    }
    // Auto-detect: \r\n, \n, \r
    if (input[pos] === "\r" && input[pos + 1] === "\n") {
      return { match: true, length: 2 };
    }
    if (input[pos] === "\n") {
      return { match: true, length: 1 };
    }
    if (input[pos] === "\r") {
      return { match: true, length: 1 };
    }
    return { match: false, length: 0 };
  };

  while (i < input.length) {
    const ch = input[i];

    if (inQuotes) {
      if (ch === quote) {
        if (i + 1 < input.length && input[i + 1] === quote) {
          current += ch + input[i + 1];
          i += 2;
          continue;
        }
        inQuotes = false;
        current += ch;
        i++;
        continue;
      }
      current += ch;
      i++;
    } else {
      const sep = isLineSep(i);
      if (sep.match) {
        lines.push(current);
        current = "";
        i += sep.length;
        continue;
      }
      if (ch === quote) {
        inQuotes = true;
        current += ch;
        i++;
        continue;
      }
      current += ch;
      i++;
    }
  }

  // Push last line if non-empty (handles missing trailing newline)
  if (current.length > 0) {
    lines.push(current);
  }

  return lines;
}

/**
 * Build a CSVResult object with the helper methods attached.
 */
function buildResult(
  rows: CSVRow[],
  headers: string[],
  errors: CSVError[]
): CSVResult {
  const result: CSVResult = {
    rows,
    headers,
    errors,

    filter(predicate: (row: CSVRow) => boolean): CSVResult {
      return buildResult(rows.filter(predicate), headers, errors);
    },

    sum(column: string): number {
      let total = 0;
      for (const row of rows) {
        const val = row[column];
        if (typeof val === "number") {
          total += val;
        }
      }
      return total;
    },

    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const val = row[column];
        if (typeof val === "number") {
          total += val;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<unknown, CSVRow[]> {
      const map = new Map<unknown, CSVRow[]>();
      for (const row of rows) {
        const key = row[column];
        if (!map.has(key)) {
          map.set(key, []);
        }
        map.get(key)!.push(row);
      }
      return map;
    },
  };

  return result;
}

// ============================================================================
// Main export
// ============================================================================

/**
 * Parse a CSV string into a structured CSVResult.
 *
 * @param input   - The raw CSV string to parse.
 * @param options - Optional configuration (delimiter, quote, lineSeparator, typeCoercion).
 * @returns A CSVResult containing rows, headers, errors, and helper methods.
 */
export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator;
  const typeCoercion = options?.typeCoercion ?? true;

  // Edge case: completely empty input
  if (input.trim() === "") {
    return buildResult([], [], []);
  }

  // Split input into logical lines (respecting quoted newlines)
  const rawLines = splitLines(input, lineSeparator, quote);

  if (rawLines.length === 0) {
    return buildResult([], [], []);
  }

  // First line is the header row
  const headerParse = parseFields(rawLines[0], delimiter, quote);
  const headers = headerParse.fields.map((h) => h.trim());

  const rows: CSVRow[] = [];
  const errors: CSVError[] = [];

  // Parse each subsequent line as a data row
  for (let i = 1; i < rawLines.length; i++) {
    const line = rawLines[i];

    // Skip completely blank lines
    if (line.trim() === "") continue;

    try {
      const parsed = parseFields(line, delimiter, quote);

      if (!parsed.complete) {
        errors.push({
          row: i + 1, // 1-based, header is row 1
          message: `Unclosed quoted field`,
        });
        continue;
      }

      const fields = parsed.fields;

      // Validate field count
      if (fields.length !== headers.length) {
        errors.push({
          row: i + 1,
          message: `Expected ${headers.length} fields but found ${fields.length}`,
        });
        // Still attempt to build the row with available data
        // but only if there's at least one field with content
        if (fields.length === 1 && fields[0].trim() === "") {
          continue; // truly empty line after trim
        }
      }

      const row: CSVRow = {};
      for (let j = 0; j < headers.length; j++) {
        const raw = j < fields.length ? fields[j] : "";
        row[headers[j]] = typeCoercion ? coerceValue(raw) : raw;
      }

      rows.push(row);
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : String(err);
      errors.push({
        row: i + 1,
        message: `Parse error: ${msg}`,
      });
    }
  }

  return buildResult(rows, headers, errors);
}

// ============================================================================
// CSV Parser — Comprehensive Test Suite
// ============================================================================
// Run with: npx ts-node csv-parser.test.ts  (or tsx, etc.)
// No test framework — plain assertions that throw on failure.
// ============================================================================

import { parseCSV, CSVResult, CSVRow } from "./csv-parser";

let passed = 0;
let failed = 0;
const failures: string[] = [];

function assert(condition: boolean, message: string): void {
  if (!condition) {
    failed++;
    failures.push(message);
    console.error(`  ✗ FAIL: ${message}`);
  } else {
    passed++;
    console.log(`  ✓ ${message}`);
  }
}

function assertEqual(actual: unknown, expected: unknown, message: string): void {
  const a = JSON.stringify(actual);
  const e = JSON.stringify(expected);
  if (a !== e) {
    failed++;
    const detail = `${message}\n      expected: ${e}\n      actual:   ${a}`;
    failures.push(detail);
    console.error(`  ✗ FAIL: ${detail}`);
  } else {
    passed++;
    console.log(`  ✓ ${message}`);
  }
}

function assertClose(actual: number, expected: number, epsilon: number, message: string): void {
  if (Math.abs(actual - expected) > epsilon) {
    failed++;
    const detail = `${message} — expected ~${expected}, got ${actual}`;
    failures.push(detail);
    console.error(`  ✗ FAIL: ${detail}`);
  } else {
    passed++;
    console.log(`  ✓ ${message}`);
  }
}

function section(name: string): void {
  console.log(`\n═══ ${name} ═══`);
}

