// 7. FILTER FUNCTIONALITY
// ============================================================================
section("Filter Functionality");

(() => {
  const csv = `name,age,city
Alice,30,New York
Bob,25,Los Angeles
Charlie,35,Chicago
Diana,28,New York`;

  const result = parseCSV(csv);

  // Filter by city
  const nyResult = result.filter((row) => row["city"] === "New York");
  assertEqual(nyResult.rows.length, 2, "filter: 2 New York rows");
  assertEqual(nyResult.rows[0]["name"], "Alice", "filter: first NY row");
  assertEqual(nyResult.rows[1]["name"], "Diana", "filter: second NY row");

  // Filter by age > 28
  const olderResult = result.filter((row) => (row["age"] as number) > 28);
  assertEqual(olderResult.rows.length, 2, "filter: 2 rows with age > 28");

  // Headers preserved after filter
  assertEqual(nyResult.headers, result.headers, "filter: headers preserved");

  // Errors preserved after filter
  assertEqual(nyResult.errors, result.errors, "filter: errors preserved");

  // Filter returning no rows
  const emptyResult = result.filter(() => false);
  assertEqual(emptyResult.rows.length, 0, "filter: no matches → empty");
  assertEqual(emptyResult.headers.length, 3, "filter: headers still present when empty");

  // Chained filters
  const chained = result
    .filter((row) => (row["age"] as number) >= 28)
    .filter((row) => row["city"] === "New York");
  assertEqual(chained.rows.length, 2, "chained filter: correct count");
})();

// Filter result has working methods
(() => {
  const csv = `name,score
Alice,90
Bob,80
Charlie,70
Diana,60`;

  const result = parseCSV(csv);
  const highScores = result.filter((row) => (row["score"] as number) >= 80);

  assertEqual(highScores.count(), 2, "filtered result count() works");
  assertEqual(highScores.sum("score"), 170, "filtered result sum() works");
  assertEqual(highScores.average("score"), 85, "filtered result average() works");
})();

