section("Aggregation — groupBy()");

(() => {
  const csv = `name,dept,salary
Alice,Engineering,120000
Bob,Marketing,80000
Charlie,Engineering,110000
Diana,Marketing,90000
Eve,Engineering,130000`;

  const result = parseCSV(csv);
  const groups = result.groupBy("dept");

  assertEqual(groups.size, 2, "groupBy: 2 departments");
