// GroupBy with numeric keys
(() => {
  const csv = `name,score
Alice,10
Bob,20
Charlie,10
Diana,20
Eve,10`;

  const result = parseCSV(csv);
  const groups = result.groupBy("score");

  assertEqual(groups.get(10)!.length, 3, "groupBy numeric: 3 with score 10");
  assertEqual(groups.get(20)!.length, 2, "groupBy numeric: 2 with score 20");
})();

// ============================================================================
// 9. EDGE CASES
// ============================================================================
section("Edge Cases — Empty Input");

(() => {
  const result = parseCSV("");
  assertEqual(result.rows.length, 0, "empty string: no rows");
  assertEqual(result.headers.length, 0, "empty string: no headers");
  assertEqual(result.errors.length, 0, "empty string: no errors");
  assertEqual(result.count(), 0, "empty string: count = 0");
  assertEqual(result.sum("x"), 0, "empty string: sum = 0");
  assertEqual(result.average("x"), 0, "empty string: average = 0");
