section("Edge Cases — Single Column");

(() => {
  const csv = `id
1
2
3`;

  const result = parseCSV(csv);
  assertEqual(result.headers, ["id"], "single column: one header");
  assertEqual(result.rows.length, 3, "single column: three rows");
  assertEqual(result.rows[0]["id"], 1, "single column: first value");
