(() => {
  const csv = ` name , age , city 
Alice,30,NYC`;
  const result = parseCSV(csv);
  assertEqual(result.headers, ["name", "age", "city"], "headers are trimmed");
  assertEqual(result.rows[0]["name"], "Alice", "data accessible by trimmed header");
})();

section("Edge Cases — Unicode Content");

(() => {
  const csv = `name,emoji,description
André,🎉,"Héllo, wörld"
田中,🚀,日本語テスト`;

  const result = parseCSV(csv);
  assertEqual(result.rows[0]["name"], "André", "unicode: accented characters");
  assertEqual(result.rows[0]["emoji"], "🎉", "unicode: emoji");
  assertEqual(result.rows[0]["description"], "Héllo, wörld", "unicode: quoted with accents");
  assertEqual(result.rows[1]["name"], "田中", "unicode: CJK characters");
  assertEqual(result.rows[1]["description"], "日本語テスト", "unicode: Japanese text");
})();

section("Edge Cases — Quoted Empty String");

(() => {
  const csv = `a,b
"",value`;
  const result = parseCSV(csv);
  // A quoted empty string is still empty → null with type coercion
  assertEqual(result.rows[0]["a"], null, "quoted empty string → null");
  assertEqual(result.rows[0]["b"], "value", "field after quoted empty string");
})();

section("Edge Cases — Numbers That Should Stay Strings");

(() => {
  const csv = `val\nInfinity\nNaN\n-Infinity`;
  const result = parseCSV(csv);
  // Infinity and NaN are not finite, so they stay as strings
  assertEqual(result.rows[0]["val"], "Infinity", "Infinity stays string");
  assertEqual(result.rows[1]["val"], "NaN", "NaN stays string");
  assertEqual(result.rows[2]["val"], "-Infinity", "-Infinity stays string");
})();

section("Edge Cases — All Options Combined");

(() => {
  // Semicolon delimiter, single-quote quoting, custom line separator
  const csv = "name;value;active||'hello; world';42;true||plain;0;false";
  const result = parseCSV(csv, {
    delimiter: ";",
    quote: "'",
    lineSeparator: "||",
  });

  assertEqual(result.headers, ["name", "value", "active"], "combined options: headers");
  assertEqual(result.rows[0]["name"], "hello; world", "combined options: quoted with custom quote and delimiter");
  assertEqual(result.rows[0]["value"], 42, "combined options: number coercion");
  assertEqual(result.rows[0]["active"], true, "combined options: boolean coercion");
  assertEqual(result.rows[1]["name"], "plain", "combined options: second row");
  assertEqual(result.rows[1]["value"], 0, "combined options: zero");
  assertEqual(result.rows[1]["active"], false, "combined options: false");
})();

section("Integration — Full Workflow");

(() => {
  const csv = `product,category,price,in_stock
"Widget A",Electronics,29.99,true
"Widget B",Electronics,49.99,true
"Gadget X",Home,15.00,false
"Gadget Y",Home,25.00,true
"Tool Z",Tools,null,false
"Tool W",Tools,35.00,true`;

  const result = parseCSV(csv);

  // Basic checks
  assertEqual(result.count(), 6, "integration: total rows");
  assertEqual(result.headers.length, 4, "integration: 4 columns");

  // Sum & average
  assertClose(result.sum("price"), 154.98, 0.01, "integration: total price");
  // Average should be over the 5 numeric values (one is null)
  assertClose(result.average("price"), 154.98 / 5, 0.01, "integration: average price");

  // Filter in-stock items
  const inStock = result.filter((r) => r["in_stock"] === true);
  assertEqual(inStock.count(), 4, "integration: 4 in-stock items");
  assertClose(inStock.sum("price"), 139.98, 0.01, "integration: in-stock total");

  // GroupBy category
  const groups = result.groupBy("category");
  assertEqual(groups.size, 3, "integration: 3 categories");
  assertEqual(groups.get("Electronics")!.length, 2, "integration: 2 electronics");
  assertEqual(groups.get("Home")!.length, 2, "integration: 2 home");
  assertEqual(groups.get("Tools")!.length, 2, "integration: 2 tools");

  // Filter then groupBy
  const inStockGroups = inStock.groupBy("category");
  assertEqual(inStockGroups.get("Electronics")!.length, 2, "integration: 2 in-stock electronics");
  assertEqual(inStockGroups.get("Home")!.length, 1, "integration: 1 in-stock home");
  assertEqual(inStockGroups.get("Tools")!.length, 1, "integration: 1 in-stock tool");
})();

// ============================================================================
// RESULTS SUMMARY
// ============================================================================
console.log("\n" + "═".repeat(60));
console.log(`RESULTS: ${passed} passed, ${failed} failed, ${passed + failed} total`);
console.log("═".repeat(60));

if (failures.length > 0) {
  console.log("\nFailed tests:");
  failures.forEach((f, i) => console.log(`  ${i + 1}. ${f}`));
  process.exit(1);
} else {
  console.log("\n🎉 All tests passed!");
  process.exit(0);
}

